<?php
declare(strict_types=1);
require_once __DIR__ . '/../includes/bootstrap.php';
try{$pdo=connectDatabase();$admin=requireAdmin($pdo);}catch(Throwable $error){error_log($error->getMessage());exit('Database connection failed.');}
$flash=pullFlash();$search=trim((string)($_GET['search']??''));$filterDate=trim((string)($_GET['date']??''));if($filterDate!==''&&!validDate($filterDate))$filterDate='';$capacityDate=$filterDate?:date('Y-m-d');$editId=filter_var($_GET['edit']??null,FILTER_VALIDATE_INT)?:0;
$where=[];$params=[];if($search!==''){$where[]='(u.public_id LIKE :search_public_id OR u.full_name LIKE :search_name OR u.username LIKE :search_username OR u.phone LIKE :search_phone OR a.car_license LIKE :search_car OR m.name LIKE :search_mechanic)';$searchValue='%'.$search.'%';$params=['search_public_id'=>$searchValue,'search_name'=>$searchValue,'search_username'=>$searchValue,'search_phone'=>$searchValue,'search_car'=>$searchValue,'search_mechanic'=>$searchValue];}if($filterDate!==''){$where[]='a.appointment_date=:filter_date';$params['filter_date']=$filterDate;}$whereSql=$where?'WHERE '.implode(' AND ',$where):'';
$sql="SELECT a.*,u.public_id,u.full_name AS customer_name,u.username,u.phone AS customer_phone,m.name AS mechanic_name FROM appointments a INNER JOIN users u ON u.id=a.user_id INNER JOIN mechanics m ON m.id=a.mechanic_id {$whereSql} ORDER BY u.full_name,u.public_id,a.appointment_date";$stmt=$pdo->prepare($sql);$stmt->execute($params);$appointments=$stmt->fetchAll();
$mechanics=$pdo->query('SELECT id,name,role_title FROM mechanics WHERE is_active=1 ORDER BY id')->fetchAll();$capacityMechanics=getMechanicsWithAvailability($pdo,$capacityDate);$workshop=getWorkshopSummary($capacityMechanics);$summary=['total'=>(int)$pdo->query('SELECT COUNT(*) FROM appointments')->fetchColumn(),'customers'=>(int)$pdo->query('SELECT COUNT(*) FROM users WHERE admin_flag=0')->fetchColumn(),'free'=>$workshop['free'],'full'=>$workshop['full']];$editAppointment=null;if($editId){$e=$pdo->prepare('SELECT a.*,u.public_id,u.full_name AS customer_name,u.phone AS customer_phone,m.name AS mechanic_name FROM appointments a INNER JOIN users u ON u.id=a.user_id INNER JOIN mechanics m ON m.id=a.mechanic_id WHERE a.id=:id');$e->execute(['id'=>$editId]);$editAppointment=$e->fetch()?:null;}
?>
