e="<?= (int)$a['id'] ?>"><button class="edit-button complete-button" type="submit">✓ Complete</button></form><?php endif; ?></td></tr><?php endforeach; ?><?php if(!$appointments): ?><tr><td class="empty-table" colspan="9">No appointments found.</td></tr><?php endif; ?></tbody></table></div></article></div>
