ability.</p><div class="edit-actions"><a class="btn btn-secondary" href="<?= e(appUrl('admin/index.php')) ?>">Cancel</a><button class="btn btn-primary" id="saveChangesButton" type="submit">Save Changes</button></div></form><?php else: ?><div class="edit-empty"><span>✎</span><p>Select an appointment to assign its time or change its date and mechanic.</p></div><?php endif; ?></article>
